384	[profile.release]
385	strip = true
386	lto = "fat"
387	
388	# This profile is meant to mimic the `release` profile as closely as
389	# possible, but using settings that are more beneficial for iterative
390	# development. That is, the `release` profile is intended for actually
391	# building the release, where as `profiling` is meant for building `uv`
392	# for running benchmarks.
393	#
394	# The main differences here are to avoid stripping debug information
395	# and disabling lto. This does result in a mismatch between our release
396	# configuration and our benchmarking configuration, which is unfortunate.
397	# But compile times with `lto = true` are completely untenable:
398	#
399	#     $ cargo b --profile profiling -p uv
400	#        Compiling uv-cli v0.0.1 (/home/andrew/astral/uv/crates/uv-cli)
401	#        Compiling uv v0.2.34 (/home/andrew/astral/uv/crates/uv)
402	#         Finished `profiling` profile [optimized + debuginfo] target(s) in 3m 47s
403	#
404	# Using `lto = "thin"` brings a massive improvement, but it's still slow:
405	#
406	#     $ cargo b --profile profiling -p uv
407	#        Compiling uv v0.2.34 (/home/andrew/astral/uv/crates/uv)
408	#         Finished `profiling` profile [optimized + debuginfo] target(s) in 53.98s
409	#
410	# But with `lto = false`:
411	#
412	#     $ cargo b --profile profiling -p uv
413	#        Compiling uv v0.2.34 (/home/andrew/astral/uv/crates/uv)
414	#         Finished `profiling` profile [optimized + debuginfo] target(s) in 30.09s
415	#
416	# We get more reasonable-ish compile times. At least, it's not enough
417	# time to get up and get a cup of coffee before it completes.
418	#
419	# This setup does risk that we are measuring something in benchmarks
420	# that we are shipping, but in order to make those two the same, we'd
421	# either need to make compile times way worse for development, or take
422	# a hit to binary size and a slight hit to runtime performance in our
423	# release builds.
424	[profile.profiling]
425	inherits = "release"
426	strip = false
427	debug = "full"
428	lto = false
429	
430	# Profile for fast test execution: Skip debug info generation, and
431	# apply basic optimization, which speed up build and running tests.
432	[profile.fast-build]
433	inherits = "dev"
434	opt-level = 1
435	debug = 0
436	strip = "debuginfo"
437	
438	# Profile for faster builds: Skip debug info generation, for faster
439	# builds of smaller binaries.
440	[profile.no-debug]
441	inherits = "dev"
442	debug = 0
443	strip = "debuginfo"
444	
445	# Profile to build a minimally sized binary for uv-build
446	[profile.minimal-size]
447	inherits = "release"
448	opt-level = "z"
449	# This will still show a panic message, we only skip the unwind
450	panic = "abort"
451	codegen-units = 1
452	
453	# The profile that 'cargo dist' will build with.
454	[profile.dist]
455	inherits = "release"
